#include <stdio.h>
int maxNonAdjacentSum(int arr[], int n) {
    if (n == 0) return 0;
    if (n == 1) return arr[0];
    int dp[n];
    dp[0] = arr[0];
    dp[1] = (arr[0] > arr[1]) ? arr[0] : arr[1];
    for (int i = 2; i < n; i++) {
        dp[i] = (dp[i-1] > (dp[i-2] + arr[i])) ? dp[i-1] : (dp[i-2] + arr[i]);
    }
    return dp[n-1];
}
int main() {
    int arr[] = {2, 1, 4, 9};
    int n = sizeof(arr)/sizeof(arr[0]);
    printf("%d", maxNonAdjacentSum(arr, n));
    return 0;
}

